#include <iostream>
using namespace std;

int main() {
    int n;
    cin >> n;

    // dp[i][0] = sequences of length i ending with 0
    // dp[i][1] = sequences of length i ending with 1
    // dp[i][2] = sequences of length i ending with 2
    long long dp0 = 1, dp1 = 1, dp2 = 1; // length 1

    if (n == 1) {
        cout << 3 << endl;
        return 0;
    }

    for (int i = 2; i <= n; i++) {
        long long new0 = dp0 + dp1 + dp2;
        long long new1 = dp0 + dp2;
        long long new2 = dp0 + dp1 + dp2;
        dp0 = new0;
        dp1 = new1;
        dp2 = new2;
    }

    cout << dp0 + dp1 + dp2 << endl;
    return 0;
}
